#!/usr/bin/env node
import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const GNOSIS_MATH_ROOT = path.join(
  process.cwd(),
  'open-source/gnosis-math/Gnosis'
);
const AUDIT_PATH = path.join(
  process.cwd(),
  'apps/mcp-superserver/src/ledger-tool-audit.generated.json'
);
const REPORT_PATH = path.join(
  process.cwd(),
  'open-source/gnosis-math/MCP_GAP_LEDGER.md'
);

const SERVER_RULES = [
  [/amplituhedron|quantum|qkv|attention|wave|spectral|physics|particle|boson|fermion|vacuum|blackhole|black_hole/iu, 'quantum-mcp'],
  [/relativ|lorentz|gravity|gravit|cosmic|cosmolog|spacetime|hawking/iu, 'relativity-mcp'],
  [/thermo|heat|entropy|metabolism|temperature|landauer/iu, 'thermodynamics-mcp'],
  [/queue|ergodic|markov|harris|recurrence|stability|stationary/iu, 'ergodicity-mcp'],
  [/buley|buleyean|godformula|god_formula|kernel|sliver|clinamen|gnostic|void/iu, 'god-formula-mcp'],
  [/mesh|topolog|braid|knot|homology|betti|manifold|cobordism|fano|octonion|catmap|arnold|mckay|ade|langlands/iu, 'topology-mcp'],
  [/govern|constitution|law|justice|liability|compliance|torah|jubilee|rights/iu, 'governance-mcp'],
  [/market|hft|trading|finance|vwap|orderbook|netflix|economics|auction|tariff/iu, 'economics-mcp'],
  [/genom|dna|cancer|bio|immune|autoimmunity|cell|protein/iu, 'genomics-mcp'],
  [/sleep|dream/iu, 'sleep-mcp'],
  [/emotion|affect|anxiety|grief|forgive|recovery|therapy|mindful|psyche|conscious/iu, 'emotion-mcp'],
  [/language|linguistic|grammar|chomsky|poe|borges|leibniz|laplace|plato|aristotle|zeno|cicero|parable|witness/iu, 'philosophy-mcp'],
  [/security|adversarial|attack|deception|fraud|byzantine/iu, 'cybersecurity-mcp'],
  [/protocol|server|runtime|compiler|scheduler|forkracefold|fork_race_fold/iu, 'verification-mcp'],
];

function walkLeanFiles(directory, files = []) {
  for (const entry of readdirSync(directory, { withFileTypes: true })) {
    const fullPath = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      walkLeanFiles(fullPath, files);
    } else if (entry.isFile() && entry.name.endsWith('.lean')) {
      files.push(fullPath);
    }
  }
  return files;
}

function moduleNameFromPath(filePath) {
  return path
    .relative(GNOSIS_MATH_ROOT, filePath)
    .replace(/\.lean$/u, '')
    .split(path.sep)
    .join('/');
}

function likelyServerForModule(moduleName) {
  for (const [pattern, server] of SERVER_RULES) {
    if (pattern.test(moduleName)) return server;
  }
  return 'verification-mcp';
}

function countPattern(source, pattern) {
  return [...source.matchAll(pattern)].length;
}

function stripLeanComments(source) {
  let output = '';
  for (let index = 0; index < source.length; ) {
    if (source.startsWith('/-', index)) {
      let depth = 1;
      index += 2;
      while (index < source.length && depth > 0) {
        if (source.startsWith('/-', index)) {
          depth += 1;
          index += 2;
        } else if (source.startsWith('-/', index)) {
          depth -= 1;
          index += 2;
        } else {
          index += 1;
        }
      }
    } else if (source.startsWith('--', index)) {
      while (index < source.length && source[index] !== '\n') index += 1;
    } else if (source[index] === '"') {
      output += ' ';
      index += 1;
      while (index < source.length) {
        if (source[index] === '\\') {
          output += '  ';
          index += 2;
        } else if (source[index] === '"') {
          output += ' ';
          index += 1;
          break;
        } else {
          output += source[index] === '\n' ? '\n' : ' ';
          index += 1;
        }
      }
    } else {
      output += source[index];
      index += 1;
    }
  }
  return output;
}

function extractDeclarations(source) {
  const declarations = [];
  const declarationPattern =
    /^\s*(theorem|lemma|def|structure|inductive)\s+([A-Za-z0-9_'.]+)/gmu;
  for (const match of source.matchAll(declarationPattern)) {
    declarations.push(`${match[1]} ${match[2]}`);
  }
  return declarations;
}

function readReferencedGnosisMathModules() {
  const audit = JSON.parse(readFileSync(AUDIT_PATH, 'utf8'));
  const modules = new Set();
  for (const entry of audit.entries) {
    const prefix = 'open-source/gnosis-math/Gnosis/';
    if (
      entry.proofArtifactPath.startsWith(prefix) &&
      entry.proofArtifactPath.endsWith('.lean')
    ) {
      modules.add(entry.proofArtifactPath.slice(prefix.length, -'.lean'.length));
    }
  }
  return modules;
}

function auditModule(filePath) {
  const source = readFileSync(filePath, 'utf8');
  const code = stripLeanComments(source);
  const moduleName = moduleNameFromPath(filePath);
  const declarations = extractDeclarations(code);
  return {
    module: moduleName,
    path: `open-source/gnosis-math/Gnosis/${moduleName}.lean`,
    likelyServer: likelyServerForModule(moduleName),
    theoremCount: countPattern(code, /^\s*theorem\s+/gmu),
    lemmaCount: countPattern(code, /^\s*lemma\s+/gmu),
    defCount: countPattern(code, /^\s*def\s+/gmu),
    typeCount:
      countPattern(code, /^\s*structure\s+/gmu) +
      countPattern(code, /^\s*inductive\s+/gmu),
    hasSorry: /\bsorry\b/u.test(code),
    hasAdmit: /\badmit\b/u.test(code),
    hasAxiom: /^\s*axiom\s+/mu.test(code),
    topDeclarations: declarations.slice(0, 8),
  };
}

function scoreModule(moduleAudit) {
  const proofWeight = moduleAudit.theoremCount * 3 + moduleAudit.lemmaCount * 2;
  const surfaceWeight = moduleAudit.typeCount + moduleAudit.defCount;
  const cleanlinessPenalty =
    (moduleAudit.hasSorry ? 20 : 0) +
    (moduleAudit.hasAdmit ? 20 : 0) +
    (moduleAudit.hasAxiom ? 10 : 0);
  return proofWeight + surfaceWeight - cleanlinessPenalty;
}

function renderModuleRow(moduleAudit) {
  const flags = [
    moduleAudit.hasSorry ? 'sorry' : '',
    moduleAudit.hasAdmit ? 'admit' : '',
    moduleAudit.hasAxiom ? 'axiom' : '',
  ]
    .filter(Boolean)
    .join(', ');
  const declarations =
    moduleAudit.topDeclarations.length > 0
      ? moduleAudit.topDeclarations.map((name) => `\`${name}\``).join(', ')
      : '';
  return `| \`${moduleAudit.module}\` | ${moduleAudit.likelyServer} | ${moduleAudit.theoremCount} | ${moduleAudit.lemmaCount} | ${moduleAudit.defCount} | ${moduleAudit.typeCount} | ${flags || 'clean scan'} | ${declarations} |`;
}

function renderReport(unreferenced) {
  const byServer = new Map();
  for (const moduleAudit of unreferenced) {
    const bucket = byServer.get(moduleAudit.likelyServer) ?? [];
    bucket.push(moduleAudit);
    byServer.set(moduleAudit.likelyServer, bucket);
  }
  const cleanPromotionCandidates = unreferenced.filter(
    (moduleAudit) =>
      moduleAudit.theoremCount + moduleAudit.lemmaCount > 0 &&
      !moduleAudit.hasSorry &&
      !moduleAudit.hasAdmit &&
      !moduleAudit.hasAxiom
  );

  const lines = [
    '# MCP Gap Ledger',
    '',
    'Parent: [Gnosis Math](./README.md)',
    '',
    'This report is generated by `node open-source/gnosis/scripts/audit-gnosis-math-mcp-gaps.mjs`.',
    'It compares `open-source/gnosis-math/Gnosis/**/*.lean` against the generated superserver ledger audit and lists Lean modules that are not yet referenced by MCP theorem coverage.',
    '',
    '## Summary',
    '',
    `- Unreferenced Lean modules: ${unreferenced.length}`,
    `- Clean theorem-bearing promotion candidates: ${cleanPromotionCandidates.length}`,
    `- Likely MCP islands with gaps: ${byServer.size}`,
    '',
    '## Likely MCP Island Counts',
    '',
    '| MCP island | Unreferenced modules | Clean theorem-bearing candidates |',
    '|---|---:|---:|',
  ];

  for (const [server, modules] of [...byServer.entries()].sort(([a], [b]) =>
    a.localeCompare(b)
  )) {
    const cleanCount = modules.filter(
      (moduleAudit) =>
        moduleAudit.theoremCount + moduleAudit.lemmaCount > 0 &&
        !moduleAudit.hasSorry &&
        !moduleAudit.hasAdmit &&
        !moduleAudit.hasAxiom
    ).length;
    lines.push(`| ${server} | ${modules.length} | ${cleanCount} |`);
  }

  lines.push(
    '',
    '## Highest-Value Promotion Candidates',
    '',
    '| Module | Likely MCP | Theorems | Lemmas | Defs | Types | Flags | First declarations |',
    '|---|---|---:|---:|---:|---:|---|---|'
  );

  for (const moduleAudit of [...cleanPromotionCandidates]
    .sort((left, right) => scoreModule(right) - scoreModule(left))
    .slice(0, 120)) {
    lines.push(renderModuleRow(moduleAudit));
  }

  lines.push(
    '',
    '## Full Unreferenced Module Inventory',
    '',
    '| Module | Likely MCP | Theorems | Lemmas | Defs | Types | Flags | First declarations |',
    '|---|---|---:|---:|---:|---:|---|---|'
  );

  for (const moduleAudit of [...unreferenced].sort((left, right) =>
    left.module.localeCompare(right.module)
  )) {
    lines.push(renderModuleRow(moduleAudit));
  }

  lines.push('');
  return lines.join('\n');
}

function main() {
  const referencedModules = readReferencedGnosisMathModules();
  const unreferenced = [];
  for (const leanFile of walkLeanFiles(GNOSIS_MATH_ROOT)) {
    const moduleAudit = auditModule(leanFile);
    if (!referencedModules.has(moduleAudit.module)) {
      unreferenced.push(moduleAudit);
    }
  }
  writeFileSync(REPORT_PATH, renderReport(unreferenced), 'utf8');
  console.log(`Wrote ${path.relative(process.cwd(), REPORT_PATH)}`);
}

main();
